function clean(value) { return String(value || '').trim(); }
function upper(value) { return clean(value).toUpperCase(); }
const body = $json.body || $json || {};
const proxy = (body.proxy && typeof body.proxy === 'object') ? body.proxy : {};
const purpose = clean(body.proxy_purpose || body.purpose || 'WA_REGISTRATION') || 'WA_REGISTRATION';
const requestedMode = upper(body.proxy_session_mode || body.session_mode || proxy.proxy_session_mode || proxy.session_mode || '');
const stickyAliases = new Set(['STICKY', 'PROXY_SESSION_MODE_STICKY', 'US_STICKY_DYNAMIC_IP']);
const rotatingAliases = new Set(['ROTATING', 'ROTATE', 'PROXY_SESSION_MODE_ROTATING', 'US_ROTATING_DYNAMIC_IP', 'US_RANDOM_DYNAMIC_IP']);
const proxySessionMode = stickyAliases.has(requestedMode) ? 'STICKY' : (rotatingAliases.has(requestedMode) ? 'ROTATING' : (upper(purpose).includes('REGISTRATION') ? 'STICKY' : 'ROTATING'));
const seed = `${$execution.id}-${Date.now()}-${Math.random().toString(16).slice(2)}`;
const proxyStateJSON = clean(body.proxy_state_json || body.state_json || proxy.proxy_state_json || proxy.state_json || '');
const proxyURL = clean(body.proxy_url || proxy.proxy_url || '');
return [{ json: {
  workspace_id: body.workspace_id || 'default',
  job_id: body.job_id || $execution.id,
  request_id: body.request_id || $execution.id,
  purpose,
  proxy_session_mode: proxySessionMode,
  proxy_mode: proxySessionMode === 'STICKY' ? 'US_STICKY_DYNAMIC_IP' : 'US_ROTATING_DYNAMIC_IP',
  sticky_ttl: clean(body.sticky_ttl || proxy.sticky_ttl || '600s') || '600s',
  account_id: `wa-us-dyn-${seed}`.slice(0, 120),
  selection_seed: seed,
  provided_proxy: Boolean(proxyURL || proxyStateJSON),
  proxy_url: proxyURL,
  proxy_state_json: proxyStateJSON,
} }];

function parseJSON(value) { try { return JSON.parse(String(value || '{}')); } catch { return {}; } }
const input = $('Normalize Dynamic IP Input').first().json;
const state = parseJSON(input.proxy_state_json);
