  success: Boolean(proxyURL || input.proxy_state_json),
  accepted: Boolean(proxyURL || input.proxy_state_json),
  proxy_mode: input.proxy_mode || 'PROVIDED_DYNAMIC_IP',
  proxy_session_mode: input.proxy_session_mode,
  country_code: state._gopay_country_code || state.country_code || 'US',
  account_id: accountID,
