if (statusCode < 200 || statusCode >= 300) {
  return [{ json: { success: false, accepted: false, proxy_mode: proxyMode, proxy_session_mode: input.proxy_session_mode, country_code: 'US', account_id: input.account_id, error_message: `proxy-runtime dynamic IP acquire returned HTTP ${statusCode}` } }];
}
