  return [{ json: { success: false, accepted: false, proxy_mode: proxyMode, proxy_session_mode: input.proxy_session_mode, country_code: 'US', account_id: lease.account_id || input.account_id, lease_id: lease.lease_id || '', error_message: 'proxy-runtime dynamic IP lease has no egress endpoint' } }];
